using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Columns;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Order;
using System.Collections.ObjectModel;
using System.Linq.Expressions;
using System.Reflection;
using System.Runtime.CompilerServices;

namespace Benchmarks;

/// <summary>
/// Research-only microbenchmarks for comparing js2il late-bound dispatch against
/// CLR-focused DLR call sites generated by C# <c>dynamic</c> and custom binders.
/// </summary>
[MemoryDiagnoser]
[Config(typeof(FullParamsConfig))]
[ShortRunJob]
[RankColumn]
[Orderer(SummaryOrderPolicy.FastestToSlowest)]
[HideColumns("Error", "StdDev")]
public class LateBoundDispatchBenchmarks
{
    private readonly ClrReceiver _receiver = new();
    private readonly object _receiverAsObject;
    private readonly dynamic _dynamicReceiver;
    private readonly string _noArgsMethodName = nameof(ClrReceiver.NoArgs);
    private readonly string _oneArgMethodName = nameof(ClrReceiver.OneArg);

    public LateBoundDispatchBenchmarks()
    {
        _receiverAsObject = _receiver;
        _dynamicReceiver = _receiver;
    }

    [GlobalSetup]
    public void Setup()
    {
        // Prime reflection and DLR rule caches so the benchmark focuses on steady-state dispatch.
        _ = JavaScriptRuntime.Object.CallMember0(_receiverAsObject, _noArgsMethodName);
        _ = JavaScriptRuntime.Object.CallMember1(_receiverAsObject, _oneArgMethodName, 1.0);
        _ = _dynamicReceiver.NoArgs();
        _ = _dynamicReceiver.OneArg(1.0);
        _ = RuntimeNamedCallSite0Dispatcher.Invoke(_receiverAsObject, _noArgsMethodName);
        _ = RuntimeNamedCallSite1Dispatcher.Invoke(_receiverAsObject, _oneArgMethodName, 1.0);
    }

    [Benchmark(Baseline = true, Description = "Direct CLR call (0 args)")]
    public int DirectClrCall0() => _receiver.NoArgs();

    [Benchmark(Description = "CallMember0 CLR receiver")]
    public int CallMember0_ClrReceiver() => (int)JavaScriptRuntime.Object.CallMember0(_receiverAsObject, _noArgsMethodName)!;

    [Benchmark(Description = "DLR dynamic CLR receiver (0 args)")]
    public int DynamicClrCall0() => _dynamicReceiver.NoArgs();

    [Benchmark(Description = "DLR CallSite runtime method name (0 args)")]
    public int RuntimeNamedCallSite0_ClrReceiver() => (int)RuntimeNamedCallSite0Dispatcher.Invoke(_receiverAsObject, _noArgsMethodName)!;

    [Benchmark(Description = "Direct CLR call (1 arg)")]
    public double DirectClrCall1() => _receiver.OneArg(1.0);

    [Benchmark(Description = "CallMember1 CLR receiver")]
    public double CallMember1_ClrReceiver() => (double)JavaScriptRuntime.Object.CallMember1(_receiverAsObject, _oneArgMethodName, 1.0)!;

    [Benchmark(Description = "DLR dynamic CLR receiver (1 arg)")]
    public double DynamicClrCall1() => _dynamicReceiver.OneArg(1.0);

    [Benchmark(Description = "DLR CallSite runtime method name (1 arg)")]
    public double RuntimeNamedCallSite1_ClrReceiver() => (double)RuntimeNamedCallSite1Dispatcher.Invoke(_receiverAsObject, _oneArgMethodName, 1.0)!;

    private static MethodInfo ResolveMethod(Type receiverType, string methodName, int argCount)
    {
        return receiverType
            .GetMethods(BindingFlags.Instance | BindingFlags.Public)
            .FirstOrDefault(m => string.Equals(m.Name, methodName, StringComparison.Ordinal)
                && m.GetParameters().Length == argCount)
            ?? throw new MissingMethodException(receiverType.FullName, methodName);
    }

    private static Func<object, object> CreateNoArgInvoker(Type receiverType, MethodInfo method)
    {
        var receiver = Expression.Parameter(typeof(object), "receiver");
        var call = Expression.Call(Expression.Convert(receiver, receiverType), method);
        var boxedResult = Expression.Convert(call, typeof(object));
        return Expression.Lambda<Func<object, object>>(boxedResult, receiver).Compile();
    }

    private static Func<object, object, object> CreateOneArgInvoker(Type receiverType, MethodInfo method)
    {
        var receiver = Expression.Parameter(typeof(object), "receiver");
        var argument = Expression.Parameter(typeof(object), "argument");
        var parameterType = method.GetParameters()[0].ParameterType;
        var call = Expression.Call(
            Expression.Convert(receiver, receiverType),
            method,
            Expression.Convert(argument, parameterType));
        var boxedResult = Expression.Convert(call, typeof(object));
        return Expression.Lambda<Func<object, object, object>>(boxedResult, receiver, argument).Compile();
    }

    private static class RuntimeNamedCallSite0Dispatcher
    {
        private static readonly CallSite<Func<CallSite, object, string, object>> Site =
            CallSite<Func<CallSite, object, string, object>>.Create(new RuntimeNamedInvokeBinder0());

        public static object Invoke(object receiver, string methodName) => Site.Target(Site, receiver, methodName);
    }

    private static class RuntimeNamedCallSite1Dispatcher
    {
        private static readonly CallSite<Func<CallSite, object, string, object, object>> Site =
            CallSite<Func<CallSite, object, string, object, object>>.Create(new RuntimeNamedInvokeBinder1());

        public static object Invoke(object receiver, string methodName, object arg0) => Site.Target(Site, receiver, methodName, arg0);
    }

    private sealed class RuntimeNamedInvokeBinder0 : CallSiteBinder
    {
        public override T BindDelegate<T>(CallSite<T> site, object[] args)
        {
            if (typeof(T) != typeof(Func<CallSite, object, string, object>))
            {
                return base.BindDelegate(site, args)!;
            }

            var receiverType = args[0]?.GetType() ?? throw new ArgumentNullException(nameof(args));
            var methodName = args[1] as string ?? throw new ArgumentNullException(nameof(args));
            var invoker = CreateNoArgInvoker(receiverType, ResolveMethod(receiverType, methodName, argCount: 0));

            Func<CallSite, object, string, object> rule = (callSite, receiver, runtimeMethodName) =>
            {
                if (receiver.GetType() != receiverType || !string.Equals(runtimeMethodName, methodName, StringComparison.Ordinal))
                {
                    return ((CallSite<Func<CallSite, object, string, object>>)callSite).Update(callSite, receiver, runtimeMethodName);
                }

                return invoker(receiver);
            };

            CacheTarget(rule);
            return (T)(object)rule;
        }

        public override Expression Bind(object[] args, ReadOnlyCollection<ParameterExpression> parameters, LabelTarget returnLabel)
            => throw new NotSupportedException("LateBoundDispatchBenchmarks uses BindDelegate-only DLR rules for this research benchmark.");
    }

    private sealed class RuntimeNamedInvokeBinder1 : CallSiteBinder
    {
        public override T BindDelegate<T>(CallSite<T> site, object[] args)
        {
            if (typeof(T) != typeof(Func<CallSite, object, string, object, object>))
            {
                return base.BindDelegate(site, args)!;
            }

            var receiverType = args[0]?.GetType() ?? throw new ArgumentNullException(nameof(args));
            var methodName = args[1] as string ?? throw new ArgumentNullException(nameof(args));
            var invoker = CreateOneArgInvoker(receiverType, ResolveMethod(receiverType, methodName, argCount: 1));

            Func<CallSite, object, string, object, object> rule = (callSite, receiver, runtimeMethodName, arg0) =>
            {
                if (receiver.GetType() != receiverType || !string.Equals(runtimeMethodName, methodName, StringComparison.Ordinal))
                {
                    return ((CallSite<Func<CallSite, object, string, object, object>>)callSite).Update(callSite, receiver, runtimeMethodName, arg0);
                }

                return invoker(receiver, arg0);
            };

            CacheTarget(rule);
            return (T)(object)rule;
        }

        public override Expression Bind(object[] args, ReadOnlyCollection<ParameterExpression> parameters, LabelTarget returnLabel)
            => throw new NotSupportedException("LateBoundDispatchBenchmarks uses BindDelegate-only DLR rules for this research benchmark.");
    }

    private sealed class ClrReceiver
    {
        public int NoArgs() => 42;

        public double OneArg(double value) => value + 1.0;
    }
}
